1903	static void AddNonCompressedBlock(const ZopfliOptions *options, int final,
1904	                                  const unsigned char *in, size_t instart,
1905	                                  size_t inend,
1906	                                  unsigned char *bp,
1907	                                  unsigned char **out, size_t *outsize)
1908	// options is only cast to void, so it is never dereferenced.
1909	// The input byte range [instart, inend) must be readable.  We bound its length
1910	// so the outer chunking loop and the inner byte-copy loop unwind fully (one
1911	// uncompressed block holds up to 65535 bytes, so a small range stays in a
1912	// single block).
1913	__CPROVER_requires(instart <= inend)
1914	__CPROVER_requires(inend - instart <= 8)
1915	__CPROVER_requires(__CPROVER_is_fresh(in, inend))
1916	// bp holds a bit position within the current byte, i.e. in [0, 7].
1917	__CPROVER_requires(__CPROVER_is_fresh(bp, sizeof(*bp)))
1918	__CPROVER_requires(*bp <= 7)
1919	// The output buffer obeys the ZOPFLI_APPEND_DATA allocation invariant: *outsize
1920	// is a valid logical size and *out is a fresh backing buffer with room for the
1921	// last byte plus one appended byte.
1922	__CPROVER_requires(__CPROVER_is_fresh(outsize, sizeof(*outsize)))
1923	__CPROVER_requires(*outsize >= 1 && *outsize <= __CPROVER_max_malloc_size / 2)
1924	__CPROVER_requires(__CPROVER_is_fresh(out, sizeof(*out)))
1925	__CPROVER_requires(__CPROVER_is_fresh(*out, *outsize + 1))
1926	__CPROVER_assigns(*bp, *outsize, *out, __CPROVER_object_whole(*out))
1927	// Every block flushes the bit position to a byte boundary, so bp ends at 0.
1928	__CPROVER_ensures(*bp == 0)
1929	// Each block writes at least its four-byte LEN/NLEN header, so the output grows.
1930	__CPROVER_ensures(*outsize >= __CPROVER_old(*outsize) + 4)
1931	{
1932	    size_t pos = instart;
1933	    (void)options;
1934	    for (;;)
1935	    {
1936	        size_t i;
1937	        unsigned short blocksize = 65535;
1938	        unsigned short nlen;
1939	        int currentfinal;
1940	
1941	        if (pos + blocksize > inend)
1942	            blocksize = inend - pos;
1943	        currentfinal = pos + blocksize >= inend;
1944	
1945	        nlen = ~blocksize;
1946	
1947	        AddBit(final && currentfinal, bp, out, outsize);
1948	        /* BTYPE 00 */
1949	        AddBit(0, bp, out, outsize);
1950	        AddBit(0, bp, out, outsize);
1951	
1952	        /* Any bits of input up to the next byte boundary are ignored. */
1953	        *bp = 0;
1954	
1955	        ZOPFLI_APPEND_DATA(blocksize % 256, out, outsize);
1956	        ZOPFLI_APPEND_DATA((blocksize / 256) % 256, out, outsize);
1957	        ZOPFLI_APPEND_DATA(nlen % 256, out, outsize);
1958	        ZOPFLI_APPEND_DATA((nlen / 256) % 256, out, outsize);
1959	
1960	        for (i = 0; i < blocksize; i++)
1961	        {
1962	            ZOPFLI_APPEND_DATA(in[pos + i], out, outsize);
1963	        }
1964	
1965	        if (currentfinal)
1966	            break;
1967	        pos += blocksize;
1968	    }
1969	}
